{"content": "     1|/*
     2| * SmartPlant v2 - Arduino Nano Sensor Test Sketch
     3| * 
     4| * Hardware Setup:
     5| * - Arduino Nano V3 (CH340)
     6| * - TEMT6000 light sensor: VCC->5V, GND->GND, OUT->A0
     7| * - AHT10 temp/humidity: SDA->A4, SCL->A5, GND->GND, VIN->5V (I2C address: 0x38)
     8| * - Capacitive soil moisture: VCC->5V, GND->GND, AOUT->A1
     9| * 
    10| * This sketch reads all three sensors and prints values to Serial Monitor every 2 seconds
    11| * Baud rate: 9600
    12| */
    13|
    14|#include <Wire.h>
    15|
    16|// Pin definitions
    17|const int LIGHT_PIN = A0;
    18|const int SOIL_PIN = A1;
    19|
    20|// AHT10 I2C address
    21|const int AHT10_ADDRESS = 0x38;
    22|
    23|// Timing
    24|unsigned long previousMillis = 0;
    25|const long interval = 2000;  // 2 seconds
    26|
    27|// AHT10 calibration data
    28|float aht10Temperature = 0.0;
    29|float aht10Humidity = 0.0;
    30|
    31|void setup() {
    32|  Serial.begin(9600);
    33|  
    34|  // Initialize I2C for AHT10
    35|  Wire.begin();
    36|  
    37|  // Initialize AHT10 sensor
    38|  if (initializeAHT10()) {
    39|    Serial.println("[SmartPlant v2] AHT10 initialized successfully");
    40|  } else {
    41|    Serial.println("[SmartPlant v2] AHT10 initialization failed");
    42|  }
    43|  
    44|  Serial.println("[SmartPlant v2] System ready - starting sensor readings...");
    45|  Serial.println();
    46|}
    47|
    48|void loop() {
    49|  unsigned long currentMillis = millis();
    50|  
    51|  if (currentMillis - previousMillis >= interval) {
    52|    previousMillis = currentMillis;
    53|    
    54|    // Read all sensors
    55|    readAndPrintSensors();
    56|  }
    57|}
    58|
    59|bool initializeAHT10() {
    60|  // Send initialization command to AHT10
    61|  // Command: 0xE1, 0x08, 0x00
    62|  Wire.beginTransmission(AHT10_ADDRESS);
    63|  Wire.write(0xE1);
    64|  Wire.write(0x08);
    65|  Wire.write(0x00);
    66|  byte error = Wire.endTransmission();
    67|  
    68|  if (error != 0) {
    69|    return false;
    70|  }
    71|  
    72|  delay(10);  // Wait for initialization to complete
    73|  return true;
    74|}
    75|
    76|bool readAHT10() {
    77|  // Send measurement command to AHT10
    78|  // Command: 0xAC, 0x33, 0x00
    79|  Wire.beginTransmission(AHT10_ADDRESS);
    80|  Wire.write(0xAC);
    81|  Wire.write(0x33);
    82|  Wire.write(0x00);
    83|  byte error = Wire.endTransmission();
    84|  
    85|  if (error != 0) {
    86|    return false;
    87|  }
    88|  
    89|  delay(75);  // Wait for measurement to complete (AHT10 needs ~75ms)
    90|  
    91|  // Read 6 bytes of data
    92|  Wire.requestFrom(AHT10_ADDRESS, 6);
    93|  
    94|  if (Wire.available() < 6) {
    95|    return false;
    96|  }
    97|  
    98|  // Read the data bytes
    99|  byte statusByte = Wire.read();
   100|  byte humHigh = Wire.read();
   101|  byte humLow = Wire.read();
   102|  byte tempHigh = Wire.read();
   103|  byte tempLow = Wire.read();
   104|  byte crc = Wire.read();
   105|  
   106|  // Check if measurement is valid (bit 7 of status byte should be 0)
   107|  if (statusByte & 0x80) {
   108|    return false;
   109|  }
   110|  
   111|  // Calculate humidity
   112|  // Humidity = ((humHigh << 8) | humLow) * 100.0 / 1048576.0
   113|  uint32_t humRaw = ((uint32_t)humHigh << 8) | humLow;
   114|  aht10Humidity = (humRaw * 100.0) / 1048576.0;
   115|  
   116|  // Calculate temperature
   117|  // Temperature = ((tempHigh << 8) | tempLow) * 200.0 / 1048576.0 - 50.0
   118|  uint32_t tempRaw = ((uint32_t)tempHigh << 8) | tempLow;
   119|  aht10Temperature = (tempRaw * 200.0) / 1048576.0 - 50.0;
   120|  
   121|  return true;
   122|}
   123|
   124|float readLightSensor() {
   125|  // Read TEMT6000 analog value (0-1023)
   126|  int analogValue = analogRead(LIGHT_PIN);
   127|  
   128|  // Convert to voltage (0-5V)
   129|  float voltage = analogValue * (5.0 / 1023.0);
   130|  
   131|  // Convert voltage to approximate lux
   132|  // TEMT6000 sensitivity is approximately 0.5 µA per lux
   133|  // With 10k resistor: 1 lux ≈ 0.005 V
   134|  // Max range: ~1000 lux (approximate)
   135|  float lux = voltage * 200.0;  // Approximate conversion factor
   136|  
   137|  return lux;
   138|}
   139|
   140|int readSoilMoisture() {
   141|  // Read capacitive soil moisture sensor (raw analog value 0-1023)
   142|  // Higher values = more moisture
   143|  // Lower values = drier soil
   144|  int soilValue = analogRead(SOIL_PIN);
   145|  
   146|  return soilValue;
   147|}
   148|
   149|void readAndPrintSensors() {
   150|  // Read light sensor
   151|  float lightLux = readLightSensor();
   152|  
   153|  // Read AHT10
   154|  bool ahtSuccess = readAHT10();
   155|  
   156|  // Read soil moisture
   157|  int soilRaw = readSoilMoisture();
   158|  
   159|  // Print formatted output
   160|  Serial.print("[SmartPlant v2] --- Light: ");
   161|  Serial.print(lightLux, 1);
   162|  Serial.print(" lux | Temp: ");
   163|  
   164|  if (ahtSuccess) {
   165|    Serial.print(aht10Temperature, 1);
   166|    Serial.print(" C | Humidity: ");
   167|    Serial.print(aht10Humidity, 1);
   168|    Serial.print(" %");
   169|  } else {
   170|    Serial.print("-- C | Humidity: -- %");
   171|  }
   172|  
   173|  Serial.print(" | Soil Raw: ");
   174|  Serial.print(soilRaw);
   175|  Serial.println(" ---");
   176|}", "total_lines": 175, "file_size": 4274, "truncated": false, "is_binary": false, "is_image": false}

